{
  "product_recommendation": {
    "history_ui": "En la pantalla /auditar, agrega una sección dedicada al final de la vista principal, como una lista compacta y scrollable (mobile-first) que muestre el historial de revalidaciones IMSS/Infonavit, incluyendo fecha, resultado y cambio detectado, utilizando tarjetas simples para facilitar la lectura en dispositivos móviles.",
    "next_document_logic": "Basado en el estado actual del expediente, implementa una recomendación automática al final de la revisión, sugiriendo el siguiente documento más útil (por ejemplo, 'Sube tu recibo de sueldo') derivada del análisis interno, presentada como un botón o card destacado para guiar al usuario sin interrumpir el flujo.",
    "clarity_notification": "Muestra una notificación temporal en la pantalla /auditar, como un toast o banner en la parte superior (mobile-first), que aparezca inmediatamente después de subir o revalidar información cuando el indicador de claridad aumente, con un mensaje como '¡Excelente! Tu expediente es más claro ahora'."
  },
  "technical_recommendation": {
    "backend_contract": "Extiende las API existentes de AuditaPatron para incluir endpoints que consulten el núcleo interno por historial de revalidaciones, recomendaciones de documentos y actualizaciones de claridad, asegurando que todas las solicitudes incluyan autenticación y devuelvan datos en formato JSON ligero para minimizar latencia.",
    "frontend_integration": "Reutiliza el componente actual de /auditar en la app mobile-first; agrega el historial como una subvista dinámica, la recomendación como un hook de estado, y la notificación usando bibliotecas como React Native Toast para notificaciones no intrusivas, sin alterar el flujo principal.",
    "risk_guardrails": "Implementa validaciones en el frontend y backend para verificar integridad de datos y autenticación, asegúrate de que el núcleo interno maneje todo el procesamiento de documentos para mantener la privacidad, y agrega logs para monitoreo de errores sin exponer detalles internos."
  },
  "priority_order": ["Implementar history_ui en /auditar", "Añadir next_document_logic al flujo existente", "Incorporar clarity_notification para feedback inmediato"],
  "confidence": "high"
}
